const rawText =
  $('Agent 5 - QC Final').first().json.text ||
  'Research completed but no output was generated.';

const chatId = $('Extract Topic').first().json.chat_id;
const maxLength = 4000;

let finalReport = rawText;
const reportMatch = rawText.match(/## HOOK([\s\S]*)/);
if (reportMatch) {
  finalReport = reportMatch[0];
}

// Convert markdown to Telegram-safe HTML
finalReport = finalReport
  .replace(/## (.+)/g, '<b>$1</b>')
  .replace(/\*\*(.+?)\*\*/g, '<b>$1</b>')
  .replace(/\* (.+)/g, '• $1')
  .replace(/\[([^\]]+)\]\((https?:\/\/[^\)]+)\)/g, '<a href="$2">$1</a>')
  .replace(/&/g, '&amp;');

const chunks = [];
for (let i = 0; i < finalReport.length; i += maxLength) {
  chunks.push(finalReport.slice(i, i + maxLength));
}

if (chunks.length === 0) chunks.push('No content was generated.');

return chunks.map((chunk, index) => ({
  json: {
    text: chunks.length > 1
      ? `[Part ${index + 1} of ${chunks.length}]\n\n${chunk}`
      : chunk,
    chat_id: chatId
  }
}));

const topic = $('Extract Topic').item.json.topic;
const queries = {
  a: $('Extract Topic').item.json.query_a,
  b: $('Extract Topic').item.json.query_b,
  c: $('Extract Topic').item.json.query_c,
};

// Collect results from all 3 searches
const allItems = $input.all();
let allResults = [];
let tavilyAnswer = 'No direct answer available.';

allItems.forEach((item, searchIndex) => {
  const results = item.json.results || [];
  const answer = item.json.answer;
  if (answer) tavilyAnswer = answer;

  results.forEach((r, i) => {
    let domain = 'unknown';
    try { domain = new URL(r.url).hostname; } catch(e) {}

    const trustLevel = domain.endsWith('.gov') || domain.endsWith('.edu')
      ? 'HIGH TRUST (.gov/.edu)'
      : domain.includes('wikipedia')
      ? 'MODERATE (Wikipedia)'
      : 'REVIEW NEEDED (.com/.org)';

    allResults.push({
      domain,
      trustLevel,
      title: r.title || 'No title',
      content: r.content || 'N/A',
      url: r.url || 'N/A',
      searchIndex
    });
  });
});

// Deduplicate by URL
const seen = new Set();
allResults = allResults.filter(r => {
  if (seen.has(r.url)) return false;
  seen.add(r.url);
  return true;
});

// Sort: HIGH TRUST first
const trustOrder = { 'HIGH TRUST (.gov/.edu)': 0, 'MODERATE (Wikipedia)': 1, 'REVIEW NEEDED (.com/.org)': 2 };
allResults.sort((a, b) => (trustOrder[a.trustLevel] || 2) - (trustOrder[b.trustLevel] || 2));

const formatted = allResults.slice(0, 12).map((r, i) => {
  const queryLabel = ['Query A', 'Query B', 'Query C'][r.searchIndex] || 'Unknown';
  return `[${i + 1}] ${r.title}
Source: ${r.domain} | Trust: ${r.trustLevel} | ${queryLabel}
Snippet: ${r.content}
URL: ${r.url}`;
}).join('\n\n');

return [{
  json: {
    search_results: formatted || 'No search results found.',
    tavily_answer: tavilyAnswer,
    topic: topic,
    queries_used: `A: ${queries.a} | B: ${queries.b} | C: ${queries.c}`,
    total_results: allResults.length
  }
}];

const output = $('Agent 3 - SIFT Verifier').item.json.text;
const hasVerifiedFacts = output.includes('## VERIFIED FACTS');
const hasSources = output.includes('Source:');

if (!hasVerifiedFacts || !hasSources) {
  throw new Error('Agent 3 failed to produce verified facts. Halting pipeline.');
}

return [{ json: { verified_output: output } }];

const agent1Output = $('Agent 1 - Topic Strategist').item.json.text || '';
const topic = $('Extract Topic').item.json.topic;

// Extract lines after "## Keywords" or similar section
const keywordMatch = agent1Output.match(/##\s*Keywords?[\s\S]*?\n([\s\S]*?)(?=##|$)/i);
let keywords = [];

if (keywordMatch) {
  keywords = keywordMatch[1]
    .split('\n')
    .map(l => l.replace(/^[-*•\d.]\s*/, '').trim())
    .filter(l => l.length > 5)
    .slice(0, 3);
}

// Fallback: use topic + modifiers if Agent 1 didn't produce keywords
if (keywords.length < 3) {
  keywords = [
    topic,
    `${topic} research data statistics 2024 2025`,
    `${topic} expert analysis case study`
  ];
}

return [{
  json: {
    query_a: keywords[0] || topic,
    query_b: keywords[1] || `${topic} statistics`,
    query_c: keywords[2] || `${topic} expert insights`,
    topic: topic
  }
}];
